import{_ as e,o as a,c as i,a2 as r}from"./chunks/framework.DpRDjl8b.js";const h=JSON.parse('{"title":"Volume 0 — Vision","description":"","frontmatter":{},"headers":[],"relativePath":"volumes/00-Vision.md","filePath":"volumes/00-Vision.md","lastUpdated":1784558854000}'),o={name:"volumes/00-Vision.md"};function l(n,t,d,s,u,c){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="volume-0-—-vision" tabindex="-1">Volume 0 — Vision <a class="header-anchor" href="#volume-0-—-vision" aria-label="Permalink to &quot;Volume 0 — Vision&quot;">​</a></h1><h2 id="_0-1-presentation" tabindex="-1">0.1 Présentation <a class="header-anchor" href="#_0-1-presentation" aria-label="Permalink to &quot;0.1 Présentation&quot;">​</a></h2><h3 id="objectif" tabindex="-1">Objectif <a class="header-anchor" href="#objectif" aria-label="Permalink to &quot;Objectif&quot;">​</a></h3><p>NovelTrad 2.0 est une application de bureau (Electron + Vue 3 + TypeScript) dédiée à la traduction assistée par IA de romans, web-novels et fan-fictions. L’objectif n’est plus de produire une traduction brute : il est de transformer un chapitre source en un chapitre <strong>prêt à publier</strong>, en un seul clic.</p><h3 id="philosophie" tabindex="-1">Philosophie <a class="header-anchor" href="#philosophie" aria-label="Permalink to &quot;Philosophie&quot;">​</a></h3><ul><li><strong>Un seul bouton visible.</strong> L’utilisateur clique sur <em>Traduire le chapitre</em>. Derrière, un workflow multi-agents exécute les étapes.</li><li><strong>Autonomie totale.</strong> Aucun serveur externe obligatoire : tout fonctionne localement avec Ollama (modèles recommandés : <code>qwen3.5:9b</code> pour la qualité, <code>qwen3.5:4b</code> pour la pré-traduction rapide).</li><li><strong>Qualité prouvée.</strong> Chaque chapitre reçoit un score qualité et un rapport de cohérence.</li><li><strong>Extensibilité.</strong> Le système de plugins permet d’ajouter de nouveaux modèles, exporteurs, agents ou workflows sans toucher au cœur.</li><li><strong>Répétabilité.</strong> Chaque projet est un dossier autonome contenant sources, lexique, traductions, cache, logs et base SQLite.</li></ul><h3 id="public-vise" tabindex="-1">Public visé <a class="header-anchor" href="#public-vise" aria-label="Permalink to &quot;Public visé&quot;">​</a></h3><ol><li><strong>Traducteurs amateurs</strong> de web-novels chinois/coréens/japonais vers le français ou l’anglais.</li><li><strong>Éditeurs de fan-fictions</strong> souhaitant industrialiser la relecture.</li><li><strong>Équipes de traduction</strong> collaboratives (fichiers partagés via Git ou cloud).</li><li><strong>Développeurs</strong> voulant étendre NovelTrad via plugins.</li></ol><h3 id="fonctionnalites-principales-v1-0" tabindex="-1">Fonctionnalités principales (v1.0) <a class="header-anchor" href="#fonctionnalites-principales-v1-0" aria-label="Permalink to &quot;Fonctionnalités principales (v1.0)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ID</th><th>Feature</th><th>Priority</th></tr></thead><tbody><tr><td>F01</td><td>Gestion de projets autonomes (dossier + SQLite)</td><td>Must</td></tr><tr><td>F02</td><td>Premier lancement guidé avec détection d’Ollama</td><td>Must</td></tr><tr><td>F03</td><td>Configuration des fournisseurs IA (Ollama, OpenAI, Anthropic, Gemini, OpenRouter, LM Studio)</td><td>Must</td></tr><tr><td>F04</td><td>Lexique structuré avec alias, catégories, priorité</td><td>Must</td></tr><tr><td>F05</td><td>Translation Memory avec fuzzy matching</td><td>Must</td></tr><tr><td>F06</td><td>Workflow multi-agents (pré-traduction, traduction, cohérence, lexique, grammaire, style, polish, QA, export)</td><td>Must</td></tr><tr><td>F07</td><td>Vérification de cohérence avant/après</td><td>Must</td></tr><tr><td>F08</td><td>Score qualité global et par dimension</td><td>Must</td></tr><tr><td>F09</td><td>Export Markdown, TXT, DOCX, EPUB, HTML</td><td>Must</td></tr><tr><td>F10</td><td>Historique des versions avec diff/rollback</td><td>Must</td></tr><tr><td>F11</td><td>Traitement par lots avec file d’attente</td><td>Should</td></tr><tr><td>F12</td><td>Auto-update via GitHub Releases</td><td>Should</td></tr><tr><td>F13</td><td>Système de plugins</td><td>Could</td></tr><tr><td>F14</td><td>RAG interne sur le lexique et les chapitres déjà traduits</td><td>Could</td></tr></tbody></table><h3 id="fonctionnalites-futures-v2-0" tabindex="-1">Fonctionnalités futures (v2.0+) <a class="header-anchor" href="#fonctionnalites-futures-v2-0" aria-label="Permalink to &quot;Fonctionnalités futures (v2.0+)&quot;">​</a></h3><ul><li>Collaboration multi-utilisateurs (merge de traductions).</li><li>Marketplace de plugins et de modèles.</li><li>Mode serveur HTTP pour usage via navigateur.</li><li>Comparaison côte à côte enrichie.</li><li>Fine-tuning de modèle sur corpus projet.</li><li>Audio/speech-to-text pour relecture.</li></ul><h2 id="_0-2-analyse-des-solutions-existantes" tabindex="-1">0.2 Analyse des solutions existantes <a class="header-anchor" href="#_0-2-analyse-des-solutions-existantes" aria-label="Permalink to &quot;0.2 Analyse des solutions existantes&quot;">​</a></h2><h3 id="points-forts-du-marche" tabindex="-1">Points forts du marché <a class="header-anchor" href="#points-forts-du-marche" aria-label="Permalink to &quot;Points forts du marché&quot;">​</a></h3><ul><li><strong>GPTWnTranslator</strong> : pipeline automatique basé sur GPT.</li><li><strong>OmegaT / Trados</strong> : mémoire de traduction mature, mais interface lourde et pas d’IA native.</li><li><strong>NovelAITrans</strong> : workflow spécifique web-novel, mais peu extensible.</li><li><strong>Deepl / Google Translate</strong> : qualité générique, pas de gestion lexique propre.</li></ul><h3 id="points-faibles" tabindex="-1">Points faibles <a class="header-anchor" href="#points-faibles" aria-label="Permalink to &quot;Points faibles&quot;">​</a></h3><ul><li>Fragmentation : chaque outil fait une partie du travail.</li><li>Peu de vérification automatique de cohérence.</li><li>Gestion lexique manuelle ou inexistante.</li><li>Pas de score qualité objectif.</li><li>Dépendance aux API cloud coûteuses.</li></ul><h3 id="pourquoi-repartir-de-zero" tabindex="-1">Pourquoi repartir de zéro <a class="header-anchor" href="#pourquoi-repartir-de-zero" aria-label="Permalink to &quot;Pourquoi repartir de zéro&quot;">​</a></h3><p>La codebase v4 (PyQt6 + FastAPI Python) fonctionne mais mélange UI, backend, agents et pipeline dans un seul runtime Python. NovelTrad 2.0 adopte une architecture plus pérenne :</p><ul><li>UI moderne en Vue 3.</li><li>Runtime Node.js unique côté desktop.</li><li>Ollama comme seule dépendance IA locale.</li><li>Workflow déclaratif, observable et testable.</li><li>Système de plugins dès la conception.</li></ul><h2 id="_0-3-pourquoi-noveltrad" tabindex="-1">0.3 Pourquoi NovelTrad ? <a class="header-anchor" href="#_0-3-pourquoi-noveltrad" aria-label="Permalink to &quot;0.3 Pourquoi NovelTrad ?&quot;">​</a></h2><h3 id="differenciation" tabindex="-1">Différenciation <a class="header-anchor" href="#differenciation" aria-label="Permalink to &quot;Différenciation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Problème des traducteurs IA classiques</th><th>Solution NovelTrad 2.0</th></tr></thead><tbody><tr><td>Traduction chapitre par chapitre sans mémoire</td><td>Translation Memory persistante au niveau phrase + RAG interne</td></tr><tr><td>Perte de cohérence entre chapitres</td><td>Lexique verrouillé, alias, cohérence source/cible mesurée</td></tr><tr><td>Glossaire statique et manuel</td><td>Extraction automatique de termes candidats + suggestions IA</td></tr><tr><td>Qualité subjective</td><td>Score qualité global + rapport par dimension</td></tr><tr><td>Pipelines non reproductibles</td><td>Workflow déclaratif, snapshots d&#39;étape, retry/rollback</td></tr><tr><td>Dépendance aux API cloud</td><td>Ollama en local + providers cloud optionnels</td></tr></tbody></table><h3 id="comparatif-rapide" tabindex="-1">Comparatif rapide <a class="header-anchor" href="#comparatif-rapide" aria-label="Permalink to &quot;Comparatif rapide&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>NovelTrad</th><th>GalTransl</th><th>NovelForge</th><th>GPTWnTranslator</th></tr></thead><tbody><tr><td>Multi-agent</td><td>✅</td><td>✅</td><td>✅</td><td>❌</td></tr><tr><td>Mémoire long terme</td><td>✅</td><td>❌</td><td>✅</td><td>❌</td></tr><tr><td>EPUB export</td><td>✅</td><td>✅</td><td>❌</td><td>✅</td></tr><tr><td>Workflow structuré</td><td>✅</td><td>❌</td><td>✅</td><td>❌</td></tr><tr><td>Score qualité objectif</td><td>✅</td><td>❌</td><td>❌</td><td>❌</td></tr><tr><td>100 % local possible</td><td>✅</td><td>partiel</td><td>❌</td><td>❌</td></tr></tbody></table><p><em>(Comparatif indicatif basé sur les documentations publiques des projets.)</em></p><h2 id="_0-3-roadmap" tabindex="-1">0.3 Roadmap <a class="header-anchor" href="#_0-3-roadmap" aria-label="Permalink to &quot;0.3 Roadmap&quot;">​</a></h2><h3 id="mvp-sprints-1–4" tabindex="-1">MVP (Sprints 1–4) <a class="header-anchor" href="#mvp-sprints-1–4" aria-label="Permalink to &quot;MVP (Sprints 1–4)&quot;">​</a></h3><ul><li>Electron + Vue 3 + Vite + Pinia fonctionnel.</li><li>Création/ouverture de projet.</li><li>Écran lexique et chapitres.</li><li>SQLite + repositories.</li></ul><h3 id="version-1-0-sprints-5–12" tabindex="-1">Version 1.0 (Sprints 5–12) <a class="header-anchor" href="#version-1-0-sprints-5–12" aria-label="Permalink to &quot;Version 1.0 (Sprints 5–12)&quot;">​</a></h3><ul><li>Workflow multi-agents complet.</li><li>Translation Memory et cohérence.</li><li>Score qualité et export.</li><li>Auto-update et tests E2E.</li></ul><h3 id="version-2-0" tabindex="-1">Version 2.0 <a class="header-anchor" href="#version-2-0" aria-label="Permalink to &quot;Version 2.0&quot;">​</a></h3><ul><li>Plugins, marketplace, RAG avancé, collaboration.</li></ul><h2 id="✅-criteres-d-acceptation-de-la-vision" tabindex="-1">✅ Critères d’acceptation de la vision <a class="header-anchor" href="#✅-criteres-d-acceptation-de-la-vision" aria-label="Permalink to &quot;✅ Critères d’acceptation de la vision&quot;">​</a></h2><ul><li>[ ] Le cahier des charges fonctionnel de v1.0 est complet et priorisé (table F01–F14 avec MoSCoW).</li><li>[ ] Chaque fonctionnalité <code>Must</code> a un cas d’usage et un critère d’acceptation vérifiable dans les volumes correspondants.</li><li>[ ] La roadmap est décomposée en sprints de 1 à 2 semaines avec des livrables mesurables (Volume 24).</li><li>[ ] La différence entre NovelTrad v4 (PyQt6 + FastAPI Python monolithique) et NovelTrad 2.0 (Electron + Vue 3 + Node.js) est documentée dans ce volume.</li><li>[ ] Le positionnement produit (&quot;moteur de traduction de romans multi-agent&quot;) apparaît en haut du README et de la page d’accueil.</li></ul>',35)])])}const m=e(o,[["render",l]]);export{h as __pageData,m as default};
